import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionSecure {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to execute: ");
        String userInput = reader.readLine();

        // Sanitize user input by only allowing specific commands
        if (isValidCommand(userInput)) {
            // Execute the sanitized command
            Runtime.getRuntime().exec(userInput);
        } else {
            System.out.println("Invalid command. Please try again.");
        }
    }

    private static boolean isValidCommand(String userInput) {
        // Define a list of allowed commands or patterns
        String[] allowedCommands = {"ls", "dir", "pwd"};

        for (String cmd : allowedCommands) {
            if (userInput.equals(cmd)) {
                return true;
            }
        }

        return false;
    }
}

